import{_ as i,C as s,o as r,c as n,a4 as a,b as l,w as t,a as c,G as h,a5 as p}from"./chunks/framework.CZ62Rgnh.js";const b=JSON.parse('{"title":"Platform Personas","description":"","frontmatter":{},"headers":[],"relativePath":"overview/personas.md","filePath":"overview/personas.md"}'),d={name:"overview/personas.md"};function m(v,e,u,f,w,g){const o=s("Mermaid");return r(),n("div",null,[e[1]||(e[1]=a('<h1 id="platform-personas" tabindex="-1">Platform Personas <a class="header-anchor" href="#platform-personas" aria-label="Permalink to &quot;Platform Personas&quot;">​</a></h1><p>Platform Mesh recognizes three distinct personas that together form the ecosystem. Most platform discussions focus on two roles -- the platform team and the developers who use it. Platform Mesh introduces a third persona, the service provider, that is just as important.</p><h2 id="platform-owner" tabindex="-1">Platform Owner <a class="header-anchor" href="#platform-owner" aria-label="Permalink to &quot;Platform Owner&quot;">​</a></h2><p>The platform owner operates the Platform Mesh infrastructure: kcp, the <a href="/pr-preview/pr-80/overview/account-model.html">account model</a>, identity (Keycloak), and authorization (OpenFGA). They connect service providers to the mesh, manage the marketplace of available services, and establish the organizational policies that govern who can provide and consume services. Think of them as the operator of the marketplace itself.</p><p>Platform owners are responsible for:</p><ul><li>Deploying and operating the core <a href="/pr-preview/pr-80/overview/control-planes.html">control plane</a> (kcp, sharding, high availability)</li><li>Managing the <a href="/pr-preview/pr-80/overview/account-model.html">account hierarchy</a> (organizations, teams, environments)</li><li>Configuring identity realms and authorization policies</li><li>Onboarding service providers and granting them provider workspaces</li><li>Defining platform-wide policies that flow through the workspace hierarchy</li></ul><h2 id="service-provider" tabindex="-1">Service Provider <a class="header-anchor" href="#service-provider" aria-label="Permalink to &quot;Service Provider&quot;">​</a></h2><p>Service providers are the teams that build and operate services within the ecosystem. They define <strong>what</strong> can be ordered (the API schema) and <strong>how</strong> it gets fulfilled (the controller logic). Any team that operates a service can become a provider by exposing a Kubernetes Resource Model (KRM) API for that service.</p><p>Examples include:</p><ul><li><strong>Database teams</strong> managing PostgreSQL, MongoDB, or Redis offerings</li><li><strong>AI/ML teams</strong> providing model training, inference, and data pipeline services</li><li><strong>PKI teams</strong> offering certificate management and key rotation</li><li><strong>CI/CD teams</strong> running build pipelines and deployment automation</li><li><strong>Infrastructure teams</strong> providing Kubernetes clusters, VMs, or networking</li><li><strong>Third-party vendors</strong> integrating external SaaS products into the mesh</li></ul><p>Platform Mesh treats all of these as first-class participants with their own workspaces, their own API definitions, and their own lifecycle management. Providers are not second-class citizens behind an internal platform team -- they are independent operators with full control over how their services are built, deployed, and evolved.</p><p>For details on how providers publish APIs, integrate with the mesh, and fulfill orders, see <a href="/pr-preview/pr-80/overview/providers.html">Service Providers</a>.</p><h2 id="service-consumer" tabindex="-1">Service Consumer <a class="header-anchor" href="#service-consumer" aria-label="Permalink to &quot;Service Consumer&quot;">​</a></h2><p>Developers, data scientists, and application owners who discover services through the marketplace, order capabilities by creating resource documents, and manage their lifecycle through KRM. Consumers interact with every provider through the same tools and patterns: <code>kubectl</code>, GitOps, IaC, or the <a href="/pr-preview/pr-80/overview/architecture.html#ui-layer">Platform Mesh Portal</a>.</p><p>The consumer experience is always the same regardless of the service: declare what you want, and the platform makes it so. Whether ordering a managed database, a Kubernetes cluster, or an AI inference endpoint, consumers write a resource document describing the desired state and the provider&#39;s controller reconciles it.</p><p>For details on the consumer workflow, interaction modes, and service discovery, see <a href="/pr-preview/pr-80/overview/consumers.html">Service Consumers</a>.</p><h2 id="how-personas-interact" tabindex="-1">How Personas Interact <a class="header-anchor" href="#how-personas-interact" aria-label="Permalink to &quot;How Personas Interact&quot;">​</a></h2>',17)),(r(),l(p,null,{default:t(()=>[h(o,{id:"mermaid-104",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20PO%5B%22Platform%20Owner%22%5D%0A%20%20%20%20SP%5B%22Service%20Provider%22%5D%0A%20%20%20%20SC%5B%22Service%20Consumer%22%5D%0A%20%20%20%20PM%5B%22Platform%20Mesh%3Cbr%3E(kcp%20%2B%20Account%20Model)%22%5D%0A%20%20%20%20MP%5B%22Service%20Marketplace%3Cbr%3E(APIExports)%22%5D%0A%0A%20%20%20%20PO%20--%20%22operates%22%20--%3E%20PM%0A%20%20%20%20PO%20--%20%22onboards%22%20--%3E%20SP%0A%20%20%20%20SP%20--%20%22publishes%20APIs%20to%22%20--%3E%20MP%0A%20%20%20%20SC%20--%20%22discovers%20%26%20binds%20from%22%20--%3E%20MP%0A%20%20%20%20MP%20--%20%22hosted%20in%22%20--%3E%20PM%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<p>The platform owner sets up the infrastructure and onboards providers. Providers publish their service APIs as <a href="/pr-preview/pr-80/overview/api-export-binding.html">APIExports</a>. Consumers discover these services and bind to them, creating a self-service ecosystem where the control plane mediates all interactions.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/overview/providers.html">Service Providers</a> -- how providers publish and fulfill services</li><li><a href="/pr-preview/pr-80/overview/consumers.html">Service Consumers</a> -- how consumers discover and use services</li><li><a href="/pr-preview/pr-80/overview/integration-paths.html">Integration Paths</a> -- technical options for bringing services into the mesh</li><li><a href="/pr-preview/pr-80/overview/account-model.html">Account Model</a> -- how organizational structure maps to workspaces</li></ul>',3))])}const A=i(d,[["render",m]]);export{b as __pageData,A as default};
